import{_ as o,c as a,o as p,a1 as r}from"./chunks/framework.DP8xTkyN.js";const h=JSON.parse('{"title":"可交互的信息","description":"","frontmatter":{"title":"可交互的信息","customTag":"blog>个人思考","editLink":true,"date":"2025.09.20"},"headers":[],"relativePath":"blog/interactive-information.md","filePath":"blog/interactive-information.md","lastUpdated":1764510696000}'),n={name:"blog/interactive-information.md"};function l(i,t,s,g,e,u){return p(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="可交互的信息" tabindex="-1">可交互的信息 <a class="header-anchor" href="#可交互的信息" aria-label="Permalink to &quot;可交互的信息&quot;">​</a></h1><p>近几年一直在思考一个概念，</p><p><strong>interactive information</strong>,</p><p>即可交互性信息。</p><p>目前并没有对这个概念有官方定义，</p><p>我个人将其理解为，</p><p><strong>信息是动态，双向反馈的，</strong></p><p><strong>在不同的场景形态下，</strong></p><p><strong>能展示不同的信息量。</strong></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764484206877-generated-1764484206877-yr2y307zz4k.png" alt="图片-1"></p><h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>什么时候有这个想法呢？</p><p>我也有点记不清了，</p><p>也许是从 23 年开始，</p><p>有个模糊的想法</p><p><strong>“如何更好理解，处理信息。”</strong></p><p>同时，伴随着这几年 AI 能力的不断升级，</p><p>具体如</p><ul><li><p>LLM 能够根据对话信息生成对应的内容。</p></li><li><p>Claude 发布 Artifacts 能力，用网页承载内容信息。</p></li><li><p>Gemini 3 Pro 生成动态化，教学交互化的页面能力。</p></li></ul><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764485021204-image.png" alt=""><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764485103011-image.png" alt=""><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764485160198-img_v3_02s7_2353b26a-ade5-45b9-9a69-d92446963bdg.jpg" alt=""></p><p>作为一名信息爱好者，</p><p>在体验的过程中，</p><p>确实有种<strong>更好理解信息</strong>的感觉。</p><p>所以，</p><p>也希望记录自己的一点思考,</p><p>想法不一定完全对，</p><p>也希望一同进行交流讨论。</p><h2 id="信息演化历史" tabindex="-1">信息演化历史 <a class="header-anchor" href="#信息演化历史" aria-label="Permalink to &quot;信息演化历史&quot;">​</a></h2><blockquote><p>欲知未来，先知过去。</p></blockquote><p>《信息简史》是我很喜欢的一本书，</p><p>以时间叙事来书写信息的发展历史，</p><p>也结合本书的内容做了下简要梳理。</p><h3 id="_1-前信息理论时代-远古-19世纪" tabindex="-1">1. 前信息理论时代(远古-19世纪) <a class="header-anchor" href="#_1-前信息理论时代-远古-19世纪" aria-label="Permalink to &quot;1. 前信息理论时代(远古-19世纪)&quot;">​</a></h3><ul><li><p><strong>形态</strong>：鼓语、烽火、信鸽</p></li><li><p><strong>核心局限</strong>：信息与物理载体紧密绑定,传播低效</p></li></ul><h3 id="_2-信息固化时代-文字-印刷术" tabindex="-1">2. 信息固化时代(文字-印刷术) <a class="header-anchor" href="#_2-信息固化时代-文字-印刷术" aria-label="Permalink to &quot;2. 信息固化时代(文字-印刷术)&quot;">​</a></h3><ul><li><p><strong>形态</strong>：楔形文字、古腾堡革命</p></li><li><p><strong>突破</strong>: 信息永久化,可大规模复制</p></li><li><p><strong>局限</strong>: 信息静态,无法适应读者</p></li></ul><h3 id="_3-信息数字化萌芽-电报时代" tabindex="-1">3. 信息数字化萌芽(电报时代) <a class="header-anchor" href="#_3-信息数字化萌芽-电报时代" aria-label="Permalink to &quot;3. 信息数字化萌芽(电报时代)&quot;">​</a></h3><ul><li><p><strong>形态</strong>：摩尔斯码、电话</p></li><li><p><strong>突破</strong>: 信息与物质分离,实时传输</p></li><li><p><strong>局限</strong>: 仍是点对点,无法群体协作</p></li></ul><h3 id="_4-信息理论诞生-香农革命" tabindex="-1">4. 信息理论诞生(香农革命) <a class="header-anchor" href="#_4-信息理论诞生-香农革命" aria-label="Permalink to &quot;4. 信息理论诞生(香农革命)&quot;">​</a></h3><ul><li><p><strong>形态</strong>：1948年,信息成为可量化的数学对象</p></li><li><p><strong>意义</strong>: 奠定了所有现代通信的理论基础</p></li><li><p><strong>局限</strong>: 只关心传输效率,不关心意义和适应性</p></li></ul><h3 id="_5-信息计算时代-计算机-互联网" tabindex="-1">5. 信息计算时代(计算机-互联网) <a class="header-anchor" href="#_5-信息计算时代-计算机-互联网" aria-label="Permalink to &quot;5. 信息计算时代(计算机-互联网)&quot;">​</a></h3><ul><li><p><strong>形态</strong>： 图灵机、个人电脑、万维网、推荐系统</p></li><li><p><strong>突破</strong>: 信息可编程、可检索、可分享、可推荐</p></li><li><p><strong>局限</strong>: 信息依然静态预设，被动个性化</p></li></ul><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764486350810-generated-1764486350809-kuedck6s32k.png" alt="图片-1"><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764486493129-image.png" alt=""></p><p>在信息演化过程中，</p><p>会发现<strong>载体媒介</strong>、<strong>传播机制</strong>、<strong>传递效率</strong>都在不同优化。</p><p>这也让我们今天获取信息变得更为容易。</p><p>但貌似信息本身的内容还是偏静态的，</p><p>即意味着有下方的局限</p><p>他自身不会蕴含或延伸其他内容。</p><p>也无法获取你这里的反馈。</p><p>但近几年 LLM 的出现，</p><p><strong>使得内容动态起来了，</strong></p><p><strong>并且可以互相反馈，</strong></p><p><strong>变得更可交互了。</strong></p><h2 id="interactive-information-是什么" tabindex="-1"><strong>interactive information</strong> 是什么 <a class="header-anchor" href="#interactive-information-是什么" aria-label="Permalink to &quot;**interactive information** 是什么&quot;">​</a></h2><p><strong>个人理解</strong></p><p>实际上，<strong>interactive information</strong> 目前应该也没有确切的定义。</p><p>我姑且把它定义为**【信息是动态，双向反馈的，在不同的场景形态下，能够基于交互展示不同的信息量】**</p><p>本身从“静态存储”变成了“动态生成”</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764492106069-generated-1764492106069-ep87cv0aw5f.png" alt="优雅流动的交互信息"></p><p><strong>核心维度</strong></p><p>比较核心的几个维度</p><ol><li><p><strong>动态性</strong>：信息内容可根据上下文实时变化。</p></li><li><p><strong>双向反馈</strong>：信息能够感知接受者反馈并调整输出</p></li><li><p><strong>场景适应性</strong>：同一信息在不同场景下呈现不同的信息粒度。</p></li></ol><p>而这些维度，实际上扩展了更多的信息量。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764507332812-generated-1764507332812-1bsnbgdgk06.png" alt="图片-1"></p><p><strong>优点</strong></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764492046516-img_v3_02s7_dfa25f19-96a8-4e4a-8954-84220b0e884g.jpg" alt=""></p><ul><li><p><strong>个性化</strong>：每个人看到界面交互可能不同。</p></li><li><p><strong>降低认知负荷</strong>：只展示你需要的信息数据，适配你场景的信息粒度。</p></li><li><p><strong>双向反馈</strong>：对于用户，可以获得更多的即时反馈。</p></li><li><p><strong>非结构/非规则信息流动</strong>：非结构和非规则化的信息数据，可以脱离预设的程序流程，从而流动起来。</p></li></ul><p><strong>缺点和挑战</strong></p><ul><li><p><strong>用户体验层面</strong>：用户习惯需适应、信任问题、使用成本。</p></li><li><p><strong>技术层面</strong>：性能要求、体验要求、一致性保证性、质量控制、设计系统等等。</p></li></ul><p><strong>使用场景</strong></p><ul><li><p><strong>专题学习</strong>：根据学习者的具体情况，动态调整内容深度与探索路径。</p></li><li><p><strong>课程教育</strong>：将静态教材转化为可操作的模拟环境，让学生在参数调整与实时反馈中“从做中学”。</p></li><li><p><strong>查数提效</strong>：通过对话让数据随思维流动，自动聚合关键指标并即时生成针对性的动态分析报告。</p></li><li><p><strong>概念理解</strong>：利用多维视角切换与动态可视化演示，将晦涩的抽象定义转化为可感知的直观体验。</p></li></ul><h2 id="业界的实践" tabindex="-1">业界的实践 <a class="header-anchor" href="#业界的实践" aria-label="Permalink to &quot;业界的实践&quot;">​</a></h2><p>近几年也确实出了一些应用</p><p>在探索比较新的人机交互。</p><p>而其中有些应用，</p><p>和 <strong>interactive information</strong> 有些交集。</p><h3 id="gemini-dynamic-layout" tabindex="-1">Gemini Dynamic Layout <a class="header-anchor" href="#gemini-dynamic-layout" aria-label="Permalink to &quot;Gemini Dynamic Layout&quot;">​</a></h3><p>**定位：**根据搜索意图实时生成交互式工具和模拟器</p><p><strong>典型场景：</strong></p><ul><li><p>搜索&quot;比较旅行方案&quot; → 生成可交互的对比表</p></li><li><p>搜索&quot;计算器&quot; → 生成可用的计算工具</p></li><li><p>搜索&quot;数据可视化&quot; → 生成图表并支持参数调整</p></li></ul><p>**例子：**用动态交互的形式来了解 Transformer</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764503633641-image.png" alt=""></p><h3 id="anthropic-claude-artifacts" tabindex="-1">Anthropic Claude Artifacts <a class="header-anchor" href="#anthropic-claude-artifacts" aria-label="Permalink to &quot;Anthropic Claude Artifacts&quot;">​</a></h3><p><strong>定位</strong>：Claude Artifacts 是 Anthropic 推出的一项功能,让 Claude 在对话中能够<strong>直接生成可执行、可交互的内容</strong>。</p><p><strong>典型场景</strong>：快速原型验证、学习与教育、数据可视化、内容创作。</p><p><strong>例子</strong>：用 Claude Artifacts 生成 AI 发展时间轴</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764503498160-image.png" alt=""></p><h3 id="apps-in-chatgpt" tabindex="-1">Apps in ChatGPT <a class="header-anchor" href="#apps-in-chatgpt" aria-label="Permalink to &quot;Apps in ChatGPT&quot;">​</a></h3><p><strong>定位</strong>：将第三方应用直接嵌入 ChatGPT 对话中,通过自然语言驱动交互式界面,实现「对话即操作」</p><p><strong>典型场景</strong>：能够做旅游规划、设计创作、学习教育的场景。</p><p><strong>例子</strong>：在 ChatGPT 中对话，然后可以通过 Canvas 直接进行生图。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764503741071-image.png" alt=""></p><h3 id="阿里灵光-app" tabindex="-1">阿里灵光 App <a class="header-anchor" href="#阿里灵光-app" aria-label="Permalink to &quot;阿里灵光 App&quot;">​</a></h3><p><strong>定位</strong>：全模态 AI 助手，将“对话”转化成“可交互应用+多模态内容”，30 秒自然语言到可用小程序。</p><p><strong>典型场景</strong>：快速生成小应用，多模态创作、智能视觉理解。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764506966141-image.png" alt=""></p><h3 id="youware-响指" tabindex="-1">YouWare/响指 <a class="header-anchor" href="#youware-响指" aria-label="Permalink to &quot;YouWare/响指&quot;">​</a></h3><p><strong>定位</strong>：AI 编程社区平台,通过「氛围编程(Vibe Coding)」让非程序员也能用自然语言创建和部署 Web 应用</p><p><strong>典型场景</strong>：快速原型、代码内容社区、社区内容 Remix</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764506879623-image.png" alt=""></p><h2 id="未来假想" tabindex="-1">未来假想 <a class="header-anchor" href="#未来假想" aria-label="Permalink to &quot;未来假想&quot;">​</a></h2><p>实际上，<strong>interactive information 在不断出现</strong></p><p>个人对此比较兴奋，同时也有几点看法</p><ul><li><p><strong>信息可以适配人</strong>：随着 形态转换， GenUI 等技术成熟，以后的信息可能会越来越适配具体的人，具体的场景。</p></li><li><p>**混合 UI 交互：**虽然全文讲了较多动态交互，但现状的预设静态交互也是不可少的，两者非对立，可以混合使用。</p></li><li><p><strong>软件方式变化</strong>：软件从偏完全预设转向了部分动态内容生成，开发方式也需要适配。</p></li><li><p>**技术基建发展：**前端交互层面，动态加载，动态渲染的基建也许有发展的空间。</p></li></ul><p><strong>Information is dynamic, relatable, computable, and operates on bidirectional feedback.</strong></p><p>信息是动态，可关联，可计算的，双向反馈的。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1764508004085-image.png" alt=""></p>',108)])])}const m=o(n,[["render",l]]);export{h as __pageData,m as default};
